import React, { useState, useEffect } from "react";
import axios from "axios";

function App() {
  const [text, setText] = useState("");
  const [braille, setBraille] = useState("");
  const [loading, setLoading] = useState(false);

  // Auto translate when text changes
  useEffect(() => {
    if (text.trim() === "") {
      setBraille("");
      return;
    }

    const fetchTranslation = async () => {
      try {
        setLoading(true);

        const res = await axios.post(
          "http://localhost:5001/translate",
          { text }
        );

        setBraille(res.data.mirroredBraille);
      } catch (error) {
        console.error("Error:", error);
        setBraille("Error connecting to server");
      } finally {
        setLoading(false);
      }
    };

    const delay = setTimeout(fetchTranslation, 400); // debounce
    return () => clearTimeout(delay);
  }, [text]);

  return (
    <div style={styles.container}>
      <h1 style={styles.heading}>Braille Translator</h1>

      {/* Input Box */}
      <div style={styles.box}>
        <h3>Enter Text (Multi-language)</h3>
        <textarea
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder="Type here..."
          rows={5}
          style={styles.textarea}
        />
      </div>

      {/* Output Box */}
      <div style={styles.box}>
        <h3>Mirrored Braille Output</h3>
        <textarea
          value={loading ? "Translating..." : braille}
          readOnly
          rows={5}
          style={styles.textarea}
        />
      </div>
    </div>
  );
}

/* ---------------- STYLES ---------------- */

const styles = {
  container: {
    padding: "40px",
    fontFamily: "Arial, sans-serif",
    maxWidth: "800px",
    margin: "auto",
  },
  heading: {
    textAlign: "center",
    marginBottom: "30px",
  },
  box: {
    marginBottom: "20px",
  },
  textarea: {
    width: "100%",
    padding: "10px",
    fontSize: "16px",
    borderRadius: "8px",
    border: "1px solid #ccc",
    resize: "none",
  },
};

export default App;
